// ===== Inputs =====

// LLM delivers the text
const postText = $json.output;

// SharePoint-Match-Fields
const fields = $json.fields;

// ===== Validation =====
if (!postText) {
  throw new Error("LLM output missing");
}

if (!fields) {
  throw new Error("SharePoint-Felder missing");
}

if (!fields.request_item_id) {
  throw new Error("request_item_id missing");
}

if (!fields.jobrole_id) {
  throw new Error("jobrole_id missing");
}

if (!fields.id) {
  throw new Error("match_item_id missing");
}

// ===== Payload =====
return {
  json: {
    title: fields.Title,
    request_item_id: String(fields.request_item_id),
    jobrole_id: String(fields.jobrole_id),
    topic: fields.Title,
    generated_post: postText,
    content_status: "Review",
    language: fields.language,

    // Reference to Role_Matches
    match_item_id: String(fields.id)
  }
};

const raw = $json.value || [];   
if (!raw.length) return [];

const topics = raw
  .map(x => x.fields || {})
  .filter(f => (f.Status || "").toLowerCase() === "new")   // filter all new enties
  .map(f => ({
    topic: f.Title || null,
    request_item_id: f.id || null,
    context_type: f.Kontext_Typ || null,
    context_note: f.Kontext_Notiz || null,
    context_link: f.Kontext_Link || null,
    language: f.Sprache || null,
    match_mode: f.Match_Mode || null,
  }));

return topics.map(t => ({ json: t }));

const items = $json.value || [];

const result = items
  .filter(i => i.fields?.Aktiv === true)
  .map(i => ({
    json: {
      jobrole_id: i.fields.JobRole_ID,
      jobrole_title: i.fields.Title,
      interest_topics: i.fields.interest_topics,
      interest_keywords: i.fields.interest_keywords,
      context_focus: i.fields.context_focus,
      Exclusion_Topics: i.fields.Exclusion_Topics,
      primary_goal: i.fields.primary_goal,
      perspective: i.fields.perspective,
      tonality: i.fields.tonality,
      Pain_Points: i.fields.Pain_Points,
      Gains: i.fields.Gains,
      Value_Hook: i.fields.Value_Hooks,
      Do_Not: i.fields.Do_Not,
      Call_to_Action_Stil: i.fields.Call_to_Action_Stil,
      role_focus: i.fields.role_focus,
    }
  }));

return result;

// ===============================
// Match Topic to Relevant Jobroles
// Mode: Run once for each item
// ===============================

// -------- Get Topic (from Topic Stream) --------
const topicItem =
  $items("Select Topics for Batch")[0]?.json ||
  $items("Pick Topic (New)")[0]?.json;

if (!topicItem) {
  return {
    json: {
      ...$json,
      relevance_match: false,
      match_debug: { reason: "no_topic_item" },
    },
  };
}

// -------- Helpers --------
const toStr = (v) => (v === null || v === undefined ? "" : String(v));

const splitList = (v) =>
  toStr(v)
    .toLowerCase()
    .split(/[,;\n]+/g)
    .map((s) => s.trim())
    .filter(Boolean);

const textTokens = (v) =>
  toStr(v)
    .toLowerCase()
    .replace(/[^a-z0-9äöüß\s-]/gi, " ")
    .split(/\s+/g)
    .map((s) => s.trim())
    .filter((s) => s.length >= 3); // wichtig: ESG bleibt erhalten

const listToTokens = (list) =>
  list.flatMap((entry) => textTokens(entry));

const intersects = (a, b) => {
  const setB = new Set(b);
  return a.some((x) => setB.has(x));
};

// -------- Topic Tokens --------
const topicTitleTokens = textTokens(topicItem.topic || topicItem.Title || "");
const topicNoteTokens  = textTokens(topicItem.context_note || topicItem.Kontext_Notiz || "");
const topicTokens = [...new Set([...topicTitleTokens, ...topicNoteTokens])];

const topicFocus = Array.isArray(topicItem.context_focus)
  ? topicItem.context_focus.map((x) => String(x).toLowerCase())
  : splitList(topicItem.context_focus);

// -------- Jobrole Data (current item) --------
const interestKeywords = splitList($json.interest_keywords);
const interestTopics   = splitList($json.interest_topics);
const ausschlussThemen = splitList($json.Ausschluss_Themen);

const jobFocus = Array.isArray($json.context_focus)
  ? $json.context_focus.map((x) => String(x).toLowerCase())
  : splitList($json.context_focus);

// -------- Matching --------
// -------- Tokenize Jobrole Lists --------
const interestKeywordTokens = listToTokens(interestKeywords);
const interestTopicTokens   = listToTokens(interestTopics);
const ausschlussTokens      = listToTokens(ausschlussThemen);

// -------- Matching Logic --------

// 1) Positive Matches
const keywordMatch =
  intersects(topicTokens, interestKeywordTokens) ||
  intersects(topicTokens, interestTopicTokens);

// 2) Focus Match
const focusMatch =
  topicFocus.length > 0 &&
  jobFocus.length > 0 &&
  intersects(topicFocus, jobFocus);

// 3) Exclusion Match (HARD STOP)
const exclusionMatch =
  ausschlussThemen.length > 0 &&
  intersects(topicTokens, ausschlussThemen);

// 4) Final Relevance
const isRelevant = (keywordMatch || focusMatch) && !exclusionMatch;

// -------- Output --------
return {
  json: {
    ...$json,

    // Topic reference
    request_item_id: topicItem.request_item_id || topicItem.id,
    topic: topicItem.topic || topicItem.Title,
    context_type: topicItem.context_type || topicItem.Kontext_Typ,
    context_link: topicItem.context_link || topicItem.Kontext_Link,
    context_note: topicItem.context_note || topicItem.Kontext_Notiz,
    language: topicItem.language || topicItem.Sprache,
    match_mode: topicItem.match_mode || topicItem.Match_Mode,

    // Result
    relevance_match: isRelevant,

    // Debug 
    match_debug: {
      keywordMatch,
      focusMatch,
      exclusionMatch,
      topicFocusCount: topicFocus.length,
      topicTokenSample: topicTokens.slice(0, 10),
    },
  },
};

if ($json.fields?.content_status !== "New") {
  return null; // skip everything that is not "New"
}

return {
  json: {
    id: $json.id,
    fields: {
      content_status: "Draft"
    }
  }
};
